(function(){'use strict';const API_ENDPOINTS ={LOGIN:'/api/login'};class LoginManager{constructor(){this.init();}init(){const form = document.getElementById('loginForm');if(form){form.addEventListener('submit',(e)=> this.handleLogin(e));}const usernameInput = document.getElementById('username');if(usernameInput){usernameInput.focus();}}async handleLogin(event){event.preventDefault();const username = document.getElementById('username')?.value;const password = document.getElementById('password')?.value;const errorMessage = document.getElementById('errorMessage');if(!username || !password){this.showError('Заполните все поля');return;}if(errorMessage){errorMessage.classList.remove('show');}const submitBtn = event.target.querySelector('button[type="submit"]');if(submitBtn){submitBtn.disabled = true;submitBtn.textContent = 'Вход...';}try{const response = await fetch(API_ENDPOINTS.LOGIN,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({username,password})});const data = await response.json();if(response.ok && data.success){window.location.href = '/dashboard';}else{this.showError(data.message || 'Ошибка входа');if(submitBtn){submitBtn.disabled = false;submitBtn.textContent = 'Войти';}}}catch(error){console.error('Login error:',error);this.showError('Ошибка соединения с сервером');if(submitBtn){submitBtn.disabled = false;submitBtn.textContent = 'Войти';}}}showError(message){const errorMessage = document.getElementById('errorMessage');if(errorMessage){errorMessage.textContent = message;errorMessage.classList.add('show');setTimeout(()=>{errorMessage.classList.remove('show');},5000);}}}if(document.readyState === 'loading'){document.addEventListener('DOMContentLoaded',()=> new LoginManager());}else{new LoginManager();}})();